from dataclasses import dataclass
from enum import Enum

class ImpactSeverity(str, Enum):
    CRITICAL  = "critical"  # core feature broken; safety concern
    HIGH      = "high"      # major quality degradation; noticeable to most users
    MEDIUM    = "medium"    # quality issue; noticeable but not blocking
    LOW       = "low"       # minor polish; affects a small fraction of sessions
    COSMETIC  = "cosmetic"  # preference; does not affect task completion

SEVERITY_WEIGHTS = {
    ImpactSeverity.CRITICAL: 10,
    ImpactSeverity.HIGH:      6,
    ImpactSeverity.MEDIUM:    3,
    ImpactSeverity.LOW:       1,
    ImpactSeverity.COSMETIC:  0.3,
}

@dataclass
class FeedbackImpactScore:
    feedback_id: str
    affected_users_estimate: int
    severity: ImpactSeverity
    recurrence_per_session: float   # e.g. 0.05 = affects 5% of sessions for each affected user

    def raw_score(self) -> float:
        return (
            self.affected_users_estimate
            * SEVERITY_WEIGHTS[self.severity]
            * self.recurrence_per_session
        )

    def tier(self) -> str:
        score = self.raw_score()
        if score >= 1000:
            return "P1"
        if score >= 100:
            return "P2"
        if score >= 10:
            return "P3"
        return "P4"

    def is_safety_escalation(self) -> bool:
        return self.severity == ImpactSeverity.CRITICAL

    def sprint_recommendation(self) -> str:
        t = self.tier()
        if t == "P1":
            return "immediate: this sprint, drop other P2 items if needed"
        if t == "P2":
            return "planned: this sprint if capacity allows"
        if t == "P3":
            return "scheduled: next sprint or backlog"
        return "backlog: address when convenient"

from dataclasses import dataclass
from datetime import date

@dataclass
class BacklogHealthCheck:
    item_id: str
    created_date: date
    last_reviewed_date: date
    priority_tier: str
    model_version_at_creation: str
    current_model_version: str
    evidence_still_reproducible: bool | None = None  # None = not yet verified

    def days_since_creation(self, today: date) -> int:
        return (today - self.created_date).days

    def days_since_review(self, today: date) -> int:
        return (today - self.last_reviewed_date).days

    def is_stale(self, today: date) -> bool:
        days = self.days_since_review(today)
        if self.priority_tier == "P3" and days > 90:
            return True
        if self.priority_tier == "P4" and days > 60:
            return True
        return False

    def model_version_changed(self) -> bool:
        return self.model_version_at_creation != self.current_model_version

    def requires_revalidation(self, today: date) -> bool:
        return self.model_version_changed() and self.evidence_still_reproducible is None

    def disposition_recommendation(self, today: date) -> str:
        if self.requires_revalidation(today):
            return "RE-VALIDATE: model version changed since creation; reproduce before scheduling"
        if self.evidence_still_reproducible is False:
            return "CLOSE: resolved by model version change; confirm and close"
        if self.is_stale(today):
            return "TRIAGE: stale item; re-evaluate impact or close as won't-fix"
        return "ACTIVE: no action needed"

from dataclasses import dataclass, field
from datetime import date

@dataclass
class BacklogMetrics:
    period_start: date
    period_end: date
    items_created: int
    items_completed: int
    items_deferred_beyond_target: int
    items_closed_wont_fix: int
    positive_feedback_rate_start: float
    positive_feedback_rate_end: float

    def conversion_rate(self) -> float:
        total = self.items_created
        return self.items_completed / total if total > 0 else 0.0

    def deferral_rate(self) -> float:
        total = self.items_created
        return self.items_deferred_beyond_target / total if total > 0 else 0.0

    def quality_delta(self) -> float:
        return self.positive_feedback_rate_end - self.positive_feedback_rate_start

    def process_health(self) -> str:
        issues = []
        if self.conversion_rate() < 0.6:
            issues.append(f"low conversion rate {self.conversion_rate():.0%}: items are not getting done")
        if self.deferral_rate() > 0.3:
            issues.append(f"high deferral rate {self.deferral_rate():.0%}: over-committed in sprint planning")
        if self.quality_delta() <= 0 and self.items_completed > 0:
            issues.append("quality not improving despite completed items: review item selection")
        if not issues:
            return "HEALTHY"
        return "NEEDS ATTENTION: " + "; ".join(issues)
